SELECT filler_words, engagement_score
FROM emotional_intelligence
WHERE confidence_score > 0.8;

SELECT recording_id, AVG(words_per_second) AS avg_words_per_second
     FROM speech_patterns
     GROUP BY recording_id;

SELECT recording_id, clarity_score, engagement_score
FROM emotional_intelligence
WHERE clarity_score = (SELECT MAX(clarity_score) FROM emotional_intelligence);

SELECT title, date 
FROM recordings 
ORDER BY date DESC;
